public class Even_Odd {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

	}
	
	public void EvenOrOdd(int num) {
		if(num%2 == 0) {
			System.out.println(num + "is an even number");
			return;
		}
		System.out.println(num + "is an odd number");
	}

}
